const LANG_ORDER = ['en','pt','es','ru','de','fr','hi','id','ja','zh','th','it','tr','ko','vi','nl','uk','ar','ro','cs','ms','pl','el','jv','hu'];

let currentLang = localStorage.getItem('vd_lang') || 'pt';

function t(key) {
  return (LANGS[currentLang] || LANGS['pt'])[key] || (LANGS['pt'])[key] || key;
}

function setLang(code) {
  currentLang = code;
  localStorage.setItem('vd_lang', code);
  applyTranslations();
  document.getElementById('langMenu').classList.remove('open');
}

function applyTranslations() {
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.getAttribute('data-i18n');
    const val = t(key);
    if (el.tagName === 'INPUT') el.placeholder = val;
    else el.textContent = val;
  });
  document.querySelectorAll('[data-i18n-html]').forEach(el => {
    el.innerHTML = t(el.getAttribute('data-i18n-html')).replace(/\n/g, '<br>');
  });
  const isRtl = currentLang === 'ar';
  document.documentElement.dir = isRtl ? 'rtl' : 'ltr';
}

function buildLangSwitcher() {
  const menu = document.getElementById('langOptions');
  if (!menu) return;
  menu.innerHTML = '';
  LANG_ORDER.forEach(code => {
    const lang = LANGS[code];
    if (!lang) return;
    const btn = document.createElement('button');
    btn.className = 'lang-option' + (code === currentLang ? ' active' : '');
    btn.innerHTML = `<span class="lang-flag">${lang.flag}</span> ${lang.name}`;
    btn.onclick = () => setLang(code);
    menu.appendChild(btn);
  });
}

document.addEventListener('DOMContentLoaded', () => {
  buildLangSwitcher();
  applyTranslations();
});
